 34→public class NoUnusedImportsRule : StandardRule("no-unused-imports") {
 35→    private val ref =
 36→        mutableSetOf(
 37→            Reference("*", false),
 38→        )
 39→    private val parentExpressions = mutableSetOf<String>()
 40→    private val imports = mutableMapOf<ImportPath, ASTNode>()
 41→    private var packageName = ""
 42→    private var rootNode: ASTNode? = null
 43→    private var foundByKeyword = false
 44→
 45→    override fun beforeVisitChildNodes(
 46→        node: ASTNode,
 47→        autoCorrect: Boolean,
 48→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 49→    ) {
 50→        if (node.isRoot()) {
 51→            rootNode = node
 52→        }
 53→        when (node.elementType) {
 54→            PACKAGE_DIRECTIVE -> {
 55→                val packageDirective = node.psi as KtPackageDirective
 56→                packageName = packageDirective.qualifiedName
 57→            }
 58→            IMPORT_DIRECTIVE -> {
 59→                val importPath = (node.psi as KtImportDirective).importPath!!
 60→                if (imports.containsKey(importPath)) {
 61→                    // Emit directly when same import occurs more than once
 62→                    emit(node.startOffset, "Unused import", true)
 63→                    if (autoCorrect) {
 64→                        node.psi.delete()
 65→                    }
 66→                } else {
 67→                    imports[importPath] = node
 68→                }
 69→            }
 70→            DOT_QUALIFIED_EXPRESSION -> {
 71→                if (node.isExpressionForStaticImportWithExistingParentImport()) {
 72→                    parentExpressions.add(node.text.substringBeforeLast("("))
 73→                }
 74→            }
 75→            MARKDOWN_LINK -> {
 76→                node
 77→                    .psi
 78→                    .safeAs<KDocLink>()
 79→                    ?.let { kdocLink ->
 80→                        val linkText = kdocLink.getLinkText().removeBackticksAndTrim()
 81→                        ref.add(Reference(linkText.split('.').first(), false))
 82→                        ref.add(Reference(linkText.split('.').last(), false))
 83→                    }
 84→            }
 85→            REFERENCE_EXPRESSION, OPERATION_REFERENCE -> {
 86→                if (!node.isPartOf(IMPORT_DIRECTIVE)) {
 87→                    val identifier =
 88→                        if (node is CompositeElement) {
 89→                            node.findChildByType(IDENTIFIER)
 90→                        } else {
 91→                            node
 92→                        }
 93→                    identifier
 94→                        ?.let { identifier.text }
 95→                        ?.takeIf { it.isNotBlank() }
 96→                        ?.let {
 97→                            ref.add(
 98→                                Reference(
 99→                                    it.removeBackticksAndTrim(),
100→                                    node.psi.parentDotQualifiedExpression() != null,
101→                                ),
102→                            )
103→                        }
104→                }
105→            }
106→            BY_KEYWORD -> foundByKeyword = true
107→        }
108→    }
109→
110→    override fun afterVisitChildNodes(
111→        node: ASTNode,
112→        autoCorrect: Boolean,
113→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
114→    ) {
115→        if (node.elementType == FILE) {
116→            val directCalls = ref.filter { !it.inDotQualifiedExpression }.map { it.text }
117→            parentExpressions.forEach { parent ->
118→                imports
119→                    .filterKeys { import ->
120→                        val importPath = import.pathStr.removeBackticksAndTrim()
121→                        importPath.endsWith(".$parent") && directCalls.none { importPath.endsWith(".$it") }
122→                    }.forEach { (importPath, importNode) ->
123→                        emit(importNode.startOffset, "Unused import", true)
124→                        if (autoCorrect) {
125→                            imports.remove(importPath, importNode)
126→                            importNode.removeImportDirective()
127→                        }
128→                    }
129→            }
130→
131→            imports.forEach { (_, node) ->
132→                val importDirective = node.psi as KtImportDirective
133→                val name = importDirective.importPath?.importedName?.asString()?.removeBackticksAndTrim()
134→                val importPath = importDirective.importPath?.pathStr?.removeBackticksAndTrim()!!
135→                if (importDirective.aliasName == null &&
136→                    (packageName.isEmpty() || importPath.startsWith("$packageName.")) &&
137→                    importPath.substring(packageName.length + 1).indexOf('.') == -1
138→                ) {
139→                    emit(node.startOffset, "Unnecessary import", true)
140→                    if (autoCorrect) {
141→                        importDirective.delete()
142→                    }
143→                } else if (name != null && (!ref.map { it.text }.contains(name) || !isAValidImport(importPath)) &&
144→                    !OPERATOR_SET.contains(name) &&
145→                    !name.isComponentN() &&
146→                    !importPath.ignoreProvideDelegate()
147→                ) {
148→                    emit(node.startOffset, "Unused import", true)
149→                    if (autoCorrect) {
150→                        val nextSibling = node.nextSibling()
151→                        if (nextSibling == null) {
152→                            // Last import
153→                            node
154→                                .lastChildLeafOrSelf()
155→                                .nextLeaf()
156→                                ?.takeIf { it.isWhiteSpaceWithNewline() }
157→                                ?.let { whitespace ->
158→                                    if (node.prevLeaf() == null) {
159→                                        // Also it was the first import, and it is not preceded by any other node containing some text. So
160→                                        // all whitespace until the next is redundant
161→                                        whitespace.treeParent.removeChild(whitespace)
162→                                    } else {
163→                                        val textAfterFirstNewline =
164→                                            whitespace.text
165→                                                .substringAfter("\n")
166→                                        if (textAfterFirstNewline.isNotBlank()) {
167→                                            (whitespace as LeafElement).rawReplaceWithText(textAfterFirstNewline)
168→                                        }
169→                                    }
170→                                }
171→                        } else {
172→                            nextSibling
173→                                .takeIf { it.isWhiteSpaceWithNewline() }
174→                                ?.let { whitespace ->
175→                                    whitespace.treeParent.removeChild(whitespace)
176→                                }
177→                        }
178→                        importDirective.delete()
179→                    }
180→                }
181→            }
182→        }
183→    }
184→
185→    private fun String.ignoreProvideDelegate() =
186→        if (endsWith(".provideDelegate")) {
187→            // Ignore provideDelegate if the `by` keyword is found anywhere in the file
188→            foundByKeyword
189→        } else {
190→            false
191→        }
192→
193→    private fun ASTNode.removeImportDirective() {
194→        require(this.elementType == IMPORT_DIRECTIVE)
195→        when {
196→            treeParent.firstChildNode == this -> {
197→                nextSibling()
198→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
199→                    ?.let { it.treeParent.removeChild(it) }
200→            }
201→            treeParent.lastChildNode == this -> {
202→                prevSibling()
203→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
204→                    ?.let { it.treeParent.removeChild(it) }
205→            }
206→            else -> {
207→                nextLeaf(true)
208→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
209→                    ?.let { it.treeParent.removeChild(it) }
210→            }
211→        }
212→        treeParent.removeChild(this)
213→    }
214→
215→    private fun ASTNode.isExpressionForStaticImportWithExistingParentImport(): Boolean {
216→        if (!containsMethodCall()) {
217→            return false
218→        }
219→
220→        val methodCallExpression = text.substringBeforeLast("(")
221→
222→        // Only check static imports; identified if they start with a capital letter indicating a
223→        // class name rather than a sub-package
224→        if (methodCallExpression.isNotEmpty() && methodCallExpression[0] !in 'A'..'Z') {
225→            return false
226→        }
227→
228→        imports
229→            .filterKeys { it.pathStr.removeBackticksAndTrim().endsWith(".$methodCallExpression") }
230→            .forEach { import ->
231→                val count =
232→                    imports.count {
233→                        it.key.pathStr.removeBackticksAndTrim().startsWith(
234→                            import.key.pathStr.removeBackticksAndTrim().substringBefore(methodCallExpression),
235→                        )
236→                    }
237→                // Parent import and static import both are present
238→                if (count > 1) {
239→                    return true
240→                }
241→            }
242→        return false
243→    }
244→
245→    private fun ASTNode.containsMethodCall() = text.split(".").last().contains("(")
246→
247→    // Check if the import being checked is present in the filtered import list
248→    private fun isAValidImport(importPath: String) =
249→        imports.any {
250→            it.key.pathStr.removeBackticksAndTrim().contains(importPath)
251→        }
252→
253→    private fun String.isComponentN() = COMPONENT_N_REGEX.matches(this)
254→
255→    private fun PsiElement.parentDotQualifiedExpression(): KtDotQualifiedExpression? {
256→        val callOrThis = (parent as? KtCallExpression)?.takeIf { it.calleeExpression == this } ?: this
257→        return (callOrThis.parent as? KtDotQualifiedExpression)?.takeIf { it.selectorExpression == callOrThis }
258→    }
259→
260→    private fun String.removeBackticksAndTrim() = replace("`", "").trim()
261→
262→    private data class Reference(
263→        val text: String,
264→        val inDotQualifiedExpression: Boolean,
265→    )
266→
267→    private companion object {
268→        val COMPONENT_N_REGEX = Regex("^component\\d+$")
269→
270→        val OPERATOR_SET =
271→            setOf(
272→                // unary
273→                "unaryPlus", "unaryMinus", "not",
274→                // inc/dec
275→                "inc", "dec",
276→                // arithmetic
277→                "plus", "minus", "times", "div", "rem", "mod", "rangeTo",
278→                // in
279→                "contains",
280→                // indexed access
281→                "get", "set",
282→                // invoke
283→                "invoke",
284→                // augmented assignments
285→                "plusAssign", "minusAssign", "timesAssign", "divAssign", "modAssign",
286→                // (in)equality
287→                "equals",
288→                // comparison
289→                "compareTo",
290→                // iteration (https://github.com/shyiko/ktlint/issues/40)
291→                "iterator",
292→                // by (https://github.com/shyiko/ktlint/issues/54)
293→                "getValue", "setValue",
294→            )
295→    }
296→}
297→
298→public val NO_UNUSED_IMPORTS_RULE_ID: RuleId = NoUnusedImportsRule().ruleId
