import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class PropertyNamingRuleMutableCollectionTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given a companion object val mutable map property in lower camel case then do not emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val someMap: MutableMap<SomeKey, SomeValue> = mutableMapOf()
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a companion object val mutable map property in screaming snake case then do emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val SOME_MAP: MutableMap<SomeKey, SomeValue> = mutableMapOf()
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(3, 17, "Property name should start with a lowercase letter and use camel case")
    }

    @Test
    fun `Given an object val mutable list property without explicit type in lower camel case then do not emit`() {
        val code =
            """
            object Foo {
                val someList = mutableListOf<Int>()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level val mutable set property in lower camel case then do not emit`() {
        val code =
            """
            val someSet: MutableSet<String> = mutableSetOf()
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

